class.description:
[PckCreator] builds Godot PCK archives from files on disk. You can create a PCK in a single call with [method pck_create], or use the lower-level [method start_pck] / [method add_files] / [method finish_pck] workflow for more control. The creator supports encryption, embedding into an executable, and custom watermarks. [codeblock] # Single-call approach: pack an entire directory. var creator = PckCreator.new() creator.ver_major = 4 creator.ver_minor = 3 creator.ver_rev = 0 creator.pack_version = 2
var err = creator.pck_create("/output/game.pck", "/path/to/project") if err != OK: push_error("PCK creation failed: " + creator.get_error_message())
# Manual approach: fine-grained control. creator.reset() creator.start_pck("/output/game.pck", 2, 4, 3, 0) var files = { "/path/to/project/main.gd": "res://main.gd", "/path/to/project/icon.png": "res://icon.png", } err = creator.add_files(files) if err == OK: err = creator.finish_pck() [/codeblock]
